import React from 'react';
import {Grid, Paper} from "@material-ui/core";
import Image from './profile_pic.jpg'
const Achievements = (props) =>{
    return(
    <Grid container direction="row">
        <Paper>
            <img src = {Image} />
            <Grid item sm >
            <h1> Hello </h1>
            </Grid>
        </Paper>
    </Grid>
    );
}

export default Achievements;
